   349→    protected Class<? extends Login> defaultLoginClass() {
   350→        if (jaasContexts.containsKey(SaslConfigs.GSSAPI_MECHANISM))
   351→            return KerberosLogin.class;
   352→        if (OAuthBearerLoginModule.OAUTHBEARER_MECHANISM.equals(clientSaslMechanism))
   353→            return OAuthBearerRefreshingLogin.class;
   354→        return DefaultLogin.class;
   355→    }
