    20→import org.apache.kafka.common.KafkaException;
    21→import org.apache.kafka.common.security.JaasContext;
    22→import org.apache.kafka.common.security.auth.AuthenticateCallbackHandler;
    23→import org.apache.kafka.common.security.plain.PlainAuthenticateCallback;
    24→import org.apache.kafka.common.security.plain.PlainLoginModule;
    25→import org.apache.kafka.common.utils.Utils;
